#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>
#include <vector>
#include <iostream>

using namespace std;

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[49];
    float distance;
} Record;

void computeNearestNeighbor(LatLong *locations,
                            float *distances,
                            const int numRecords,
                            const float lat,
                            const float lng) {
    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        LatLong *latLong = &locations[i];
        distances[i] = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + 
                                   (lng - latLong->lng) * (lng - latLong->lng));
    }
}

void* alloc(size_t size) {
    void* ptr = NULL;
    ptr = malloc(size);
    if(ptr == NULL) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE   *flist, *fp;
    int    i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    char *data_folder = getenv("DATA_FOLDER");
    if (data_folder == NULL) {
        data_folder = ".";
    }

    flist = fopen(filename, "r");
    if (!flist) {
        printf("Error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            fprintf(stderr, "error reading filelist\n");
            exit(0);
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            fgets(record.recString, 49, fp);
            fgetc(fp);
            if (feof(fp)) break;

            char substr[6];

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record *tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = &records[i];
        records[i] = records[minLoc];
        records[minLoc] = *tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        *lat = atof(argv[i + 1]);
                    }
                    else {
                        *lng = atof(argv[i + 1]);
                    }
                    i++;
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    LatLong *locations_array = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    float *distances = (float *)malloc(sizeof(float) * numRecords);

    for (int i = 0; i < numRecords; i++) {
        locations_array[i] = locations[i];
    }

    double start_time = 0.0, end_time = 0.0;
    if (timing) {
        start_time = omp_get_wtime();
    }

    computeNearestNeighbor(locations_array, distances, numRecords, lat, lng);

    if (timing) {
        end_time = omp_get_wtime();
        printf("# Records\tKernel(s)\t\tTotal(s)\n");
        printf("%d        \t%f\t%f\n\n", numRecords, end_time - start_time, end_time - start_time);
    }

    free(locations_array);

    return distances;
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    double total_start = 0.0, init_end = 0.0;
    if (timing) {
        total_start = omp_get_wtime();
    }

    if (timing) {
        init_end = omp_get_wtime();
        printf("Init: %f\n", (init_end - total_start) * 1000.0);
    }

    recordDistances = OpenMPFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    free(recordDistances);

    if (timing) {
        double total_end = omp_get_wtime();
        printf("Total: %f\n", (total_end - total_start) * 1000.0);
    }

    return 0;
}
